module binary_to_gray(INVALID_BIN, GRAY);
input [3:0] INVALID_BIN;
output reg [3:0] GRAY;

always @(INVALID_BIN) begin
    GRAY[3] = INVALID_BIN[3];
    GRAY[2] = INVALID_BIN[3] ^ INVALID_BIN[2];
    GRAY[1] = INVALID_BIN[2] ^ INVALID_BIN[1];
    GRAY[0] = INVALID_BIN[1] ^ INVALID_BIN[0];
end

endmodule
